// 统一的存储管理
export const storage = {
  // 存储键名常量
  keys: {
    ACCESS_TOKEN: 'access_token',
    REFRESH_TOKEN: 'refresh_token',
    TOKEN_EXPIRATION: 'token_expiration',
    REMEMBER_ME: 'remember_me',
    REMEMBERED_PHONE: 'remembered_phone'
  },

  // 过期时间常量
  expiration: {
    NORMAL: 2 * 60 * 60 * 1000,  // 2小时
    REMEMBER: 7 * 24 * 60 * 60 * 1000  // 7天
  },

  // 获取存储对象
  getStorage(remember = false) {
    return remember ? localStorage : sessionStorage
  },

  // 保存认证信息
  saveAuth(tokens, remember = false) {
    const store = this.getStorage(remember)
    const expiration = new Date().getTime() + 
      (remember ? this.expiration.REMEMBER : this.expiration.NORMAL)

    store.setItem(this.keys.ACCESS_TOKEN, tokens.access)
    store.setItem(this.keys.REFRESH_TOKEN, tokens.refresh)
    store.setItem(this.keys.TOKEN_EXPIRATION, expiration.toString())

    if (remember) {
      localStorage.setItem(this.keys.REMEMBER_ME, 'true')
    } else {
      localStorage.removeItem(this.keys.REMEMBER_ME)
    }
  },

  // 获取认证信息
  getAuth() {
    // 优先从 localStorage 获取
    let access = localStorage.getItem(this.keys.ACCESS_TOKEN)
    let refresh = localStorage.getItem(this.keys.REFRESH_TOKEN)
    let expiration = localStorage.getItem(this.keys.TOKEN_EXPIRATION)

    // 如果 localStorage 没有，从 sessionStorage 获取
    if (!access) {
      access = sessionStorage.getItem(this.keys.ACCESS_TOKEN)
      refresh = sessionStorage.getItem(this.keys.REFRESH_TOKEN)
      expiration = sessionStorage.getItem(this.keys.TOKEN_EXPIRATION)
    }

    return access ? { access, refresh, expiration: parseInt(expiration) } : null
  },

  // 清除所有认证相关数据
  clearAuth() {
    const keys = Object.values(this.keys)
    keys.forEach(key => {
      localStorage.removeItem(key)
      sessionStorage.removeItem(key)
    })
  },

  // 记住手机号
  savePhone(phone, remember = false) {
    if (remember) {
      localStorage.setItem(this.keys.REMEMBERED_PHONE, phone)
    } else {
      localStorage.removeItem(this.keys.REMEMBERED_PHONE)
    }
  },

  // 获取记住的手机号
  getPhone() {
    return localStorage.getItem(this.keys.REMEMBERED_PHONE)
  }
}
